// Normaliza o payload de qualquer provedor para um formato único
const b = $json.body || $json;
const telefone = b.telefone || b.from || b.phone || b.sender || '';
const texto = (b.texto || b.text || b.message || b.body || '').toString().trim();
const nome = b.nome || b.senderName || b.pushName || '';

// Gatilhos diretos (não precisam de IA)
const t = texto.toLowerCase();
const optout = /\b(parar|sair|stop|cancelar inscri)/.test(t);
const pedeHumano = /\b(atendente|humano|falar com algu|pessoa|reclama)/.test(t);

return [{ json: { telefone, texto, nome, optout, pedeHumano } }];

// Extrai o texto de resposta da Lena e detecta tool calls (handoff)
const r = $json;
let resposta = '';
let transferir = false;
let resumo = '';
try {
  for (const block of (r.content || [])) {
    if (block.type === 'text') resposta += block.text;
    if (block.type === 'tool_use' && block.name === 'transferir_humano') {
      transferir = true;
      resumo = (block.input && block.input.resumo) || '';
    }
  }
} catch (e) { resposta = 'Tive um probleminha aqui. Vou te passar pra equipe 😊'; transferir = true; }
if (!resposta) resposta = 'Só um instante…';
return [{ json: { ...$json, resposta, transferir, resumo } }];
